// ---- Repository Pattern ----

// ---- Data sources ----
interface RemoteDataSource {
    suspend fun getPlayers(): List<Player>
    suspend fun getPlayer(id: Int): Player?
}

interface LocalDataSource {
    suspend fun getPlayers(): List<Player>
    suspend fun getPlayer(id: Int): Player?
    suspend fun savePlayers(players: List<Player>)
    suspend fun savePlayer(player: Player)
    suspend fun deletePlayer(id: Int)
}

// ---- Remote data source implementation ----
class RemoteDataSourceImpl(
    private val api: ApiService
) : RemoteDataSource {
    override suspend fun getPlayers(): List<Player> {
        return api.getPlayers().map { it.toDomain() }
    }

    override suspend fun getPlayer(id: Int): Player? {
        return api.getPlayer(id)?.toDomain()
    }
}

// ---- Local data source implementation ----
class LocalDataSourceImpl(
    private val dao: PlayerDao
) : LocalDataSource {
    override suspend fun getPlayers(): List<Player> {
        return dao.getAllPlayers().map { it.toDomain() }
    }

    override suspend fun getPlayer(id: Int): Player? {
        return dao.getPlayerById(id)?.toDomain()
    }

    override suspend fun savePlayers(players: List<Player>) {
        dao.insertPlayers(players.map { it.toEntity() })
    }

    override suspend fun savePlayer(player: Player) {
        dao.insertPlayer(player.toEntity())
    }

    override suspend fun deletePlayer(id: Int) {
        dao.deletePlayerById(id)
    }
}

// ---- Repository with caching ----
class CachingPlayerRepository(
    private val remote: RemoteDataSource,
    private val local: LocalDataSource
) : PlayerRepository {
    private var cache: List<Player>? = null
    private var lastFetchTime: Long = 0
    private val cacheTimeout = 60_000L // 1 minute

    override suspend fun getPlayers(): List<Player> {
        // Check cache
        val now = System.currentTimeMillis()
        if (cache != null && now - lastFetchTime < cacheTimeout) {
            return cache!!
        }

        // Try local first
        val localPlayers = local.getPlayers()
        if (localPlayers.isNotEmpty()) {
            cache = localPlayers
            lastFetchTime = now
            return localPlayers
        }

        // Fetch from remote
        try {
            val remotePlayers = remote.getPlayers()
            local.savePlayers(remotePlayers)
            cache = remotePlayers
            lastFetchTime = now
            return remotePlayers
        } catch (e: Exception) {
            // If remote fails, return whatever we have locally
            if (localPlayers.isNotEmpty()) {
                return localPlayers
            }
            throw e
        }
    }

    override suspend fun getPlayer(id: Int): Player? {
        // Try cache first
        cache?.let {
            return it.find { player -> player.id == id }
        }

        // Try local
        val localPlayer = local.getPlayer(id)
        if (localPlayer != null) {
            return localPlayer
        }

        // Try remote
        return remote.getPlayer(id)
    }

    override suspend fun savePlayer(player: Player) {
        local.savePlayer(player)
        // Invalidate cache
        cache = null
    }

    override suspend fun deletePlayer(id: Int) {
        local.deletePlayer(id)
        // Invalidate cache
        cache = null
    }

    override suspend fun updatePlayer(player: Player) {
        local.savePlayer(player)
        cache = null
    }

    fun clearCache() {
        cache = null
        lastFetchTime = 0
    }
}

// ---- Repository with offline support ----
class OfflineRepository(
    private val remote: RemoteDataSource,
    private val local: LocalDataSource
) : PlayerRepository {
    private val _networkStatus = MutableStateFlow(true)
    val networkStatus: StateFlow<Boolean> = _networkStatus.asStateFlow()

    override suspend fun getPlayers(): List<Player> {
        if (_networkStatus.value) {
            try {
                val remotePlayers = remote.getPlayers()
                local.savePlayers(remotePlayers)
                return remotePlayers
            } catch (e: Exception) {
                // Fall back to local
                return local.getPlayers()
            }
        } else {
            return local.getPlayers()
        }
    }

    override suspend fun getPlayer(id: Int): Player? {
        if (_networkStatus.value) {
            try {
                val remotePlayer = remote.getPlayer(id)
                if (remotePlayer != null) {
                    local.savePlayer(remotePlayer)
                }
                return remotePlayer
            } catch (e: Exception) {
                return local.getPlayer(id)
            }
        } else {
            return local.getPlayer(id)
        }
    }

    override suspend fun savePlayer(player: Player) {
        if (_networkStatus.value) {
            try {
                // Save to remote (if API supports)
                // Then save locally
                local.savePlayer(player)
            } catch (e: Exception) {
                // Queue for sync later
                local.savePlayer(player)
            }
        } else {
            local.savePlayer(player)
            // Queue for sync later
        }
    }

    override suspend fun deletePlayer(id: Int) {
        local.deletePlayer(id)
        if (_networkStatus.value) {
            try {
                // Delete from remote
            } catch (e: Exception) {
                // Queue for sync later
            }
        }
    }

    override suspend fun updatePlayer(player: Player) {
        savePlayer(player)
    }
}

// ---- ViewModel with Repository ----
class RepositoryViewModel(
    private val repository: PlayerRepository
) : ViewModel() {
    private val _players = MutableStateFlow<List<Player>>(emptyList())
    val players: StateFlow<List<Player>> = _players.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error.asStateFlow()

    fun loadPlayers() {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                _players.value = repository.getPlayers()
                _error.value = null
            } catch (e: Exception) {
                _error.value = e.message
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun clearError() {
        _error.value = null
    }
}

