package com.example.repository

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

// ---- Data sources ----
interface LocalSource {
    suspend fun getData(): List<String>
}

interface RemoteSource {
    suspend fun getData(): List<String>
}

// ---- Data source implementations ----
class LocalSourceImpl : LocalSource {
    override suspend fun getData(): List<String> {
        return listOf("Local Data 1", "Local Data 2")
    }
}

class RemoteSourceImpl : RemoteSource {
    override suspend fun getData(): List<String> {
        delay(1000)
        return listOf("Remote Data A", "Remote Data B", "Remote Data C")
    }
}

// ---- Repository ----
interface Repository {
    suspend fun getData(): List<String>
    fun clearCache()
}

class RepositoryImpl(
    private val local: LocalSource,
    private val remote: RemoteSource
) : Repository {
    private var cache: List<String>? = null
    private var lastFetch: Long = 0
    private val cacheTimeout = 5000L

    override suspend fun getData(): List<String> {
        val now = System.currentTimeMillis()

        // Check cache
        if (cache != null && now - lastFetch < cacheTimeout) {
            return cache!!
        }

        // Try local
        try {
            val localData = local.getData()
            cache = localData
            lastFetch = now
            return localData
        } catch (e: Exception) {
            // Local failed
        }

        // Try remote
        try {
            val remoteData = remote.getData()
            cache = remoteData
            lastFetch = now
            return remoteData
        } catch (e: Exception) {
            // Return whatever we have
            return cache ?: emptyList()
        }
    }

    override fun clearCache() {
        cache = null
        lastFetch = 0
    }
}

// ---- ViewModel ----
class RepositoryViewModel(
    private val repository: Repository
) : ViewModel() {
    data class UiState(
        val data: List<String> = emptyList(),
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    fun loadData() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                val data = repository.getData()
                _uiState.update { it.copy(data = data, isLoading = false) }
            } catch (e: Exception) {
                _uiState.update { it.copy(error = e.message, isLoading = false) }
            }
        }
    }
}

class RepositoryViewModelFactory(
    private val repository: Repository
) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(RepositoryViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return RepositoryViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

@Composable
fun RepositoryApp() {
    val repository = RepositoryImpl(LocalSourceImpl(), RemoteSourceImpl())
    val viewModel: RepositoryViewModel = viewModel(factory = RepositoryViewModelFactory(repository))

    val uiState by viewModel.uiState.collectAsState()

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        if (uiState.isLoading) {
            CircularProgressIndicator()
        }

        if (uiState.error != null) {
            Text("Error: ${uiState.error}", color = MaterialTheme.colorScheme.error)
        }

        uiState.data.forEach { item ->
            Card(modifier = Modifier.fillMaxWidth(), elevation = CardDefaults.cardElevation(2.dp)) {
                Text(item, modifier = Modifier.padding(16.dp))
            }
        }

        Button(onClick = { viewModel.loadData() }) {
            Text("Load Data")
        }

        Button(onClick = { repository.clearCache() }) {
            Text("Clear Cache")
        }
    }
}
